def total(numbers: list[int]) -> int:
    result = 0
    for n in numbers:
        result += n
    return result

class Counter:
    def __init__(self) -> None:
        self._count = 0

    def increment(self) -> int:
        self._count += 1
        return self._count

    def value(self) -> int:
        return self._count

from dataclasses import dataclass


@dataclass
class User:
    id: int
    email: str

    def domain(self) -> str:
        return self.email.split('@', 1)[1]

class Person:
    def __init__(self, first: str, last: str) -> None:
        self.first = first
        self.last = last

    @property
    def full_name(self) -> str:
        return f'{self.first} {self.last}'

def write_lines(path: str, lines: list[str]) -> None:
    with open(path, 'w', encoding='utf-8') as f:
        for line in lines:
            f.write(line + '\n')

import json


def load_json(path: str) -> dict:
    with open(path, encoding='utf-8') as f:
        return json.load(f)

from functools import wraps
from typing import Callable


def uppercase(fn: Callable[[], str]) -> Callable[[], str]:
    @wraps(fn)
    def wrapper() -> str:
        return fn().upper()

    return wrapper

from collections.abc import Iterator


def range_step(start: int, stop: int, step: int = 1) -> Iterator[int]:
    value = start
    while value < stop:
        yield value
        value += step

class ValidationError(Exception):
    def __init__(self, field: str, message: str) -> None:
        super().__init__(message)
        self.field = field


def validate_non_empty(value: str, field: str) -> str:
    if not value.strip():
        raise ValidationError(field, 'must not be empty')
    return value

from pathlib import Path


def list_py_files(directory: str) -> list[str]:
    return sorted(p.name for p in Path(directory).glob('*.py'))

from collections import defaultdict


def group_by_first_letter(words: list[str]) -> dict[str, list[str]]:
    groups: dict[str, list[str]] = defaultdict(list)
    for word in words:
        if word:
            groups[word[0].lower()].append(word)
    return dict(groups)

from collections import Counter


def word_freq(text: str) -> dict[str, int]:
    return dict(Counter(word.lower() for word in text.split()))

from abc import ABC, abstractmethod


class Storage(ABC):
    @abstractmethod
    def save(self, key: str, value: str) -> None:
        ...


class MemoryStorage(Storage):
    def __init__(self) -> None:
        self._data: dict[str, str] = {}

    def save(self, key: str, value: str) -> None:
        self._data[key] = value

class Timer:
    def __enter__(self) -> 'Timer':
        self.elapsed = 0.0
        return self

    def __exit__(self, exc_type, exc, tb) -> None:
        return None

def fetch_user_name(conn, user_id: int) -> str | None:
    row = conn.execute('SELECT name FROM users WHERE id = ?', (user_id,)).fetchone()
    return row[0] if row else None

from typing import TypedDict


class UserRow(TypedDict):
    id: int
    name: str


def as_row(user_id: int, name: str) -> UserRow:
    return {'id': user_id, 'name': name}

import asyncio


async def fetch_status(code: int) -> str:
    await asyncio.sleep(0)
    return status_label(code)


def status_label(code: int) -> str:
    return 'OK' if code == 200 else 'Error'

def is_palindrome(text: str) -> bool:
    cleaned = ''.join(ch.lower() for ch in text if ch.isalnum())
    return cleaned == cleaned[::-1]

def parse_kv(line: str) -> tuple[str, str]:
    key, value = line.split('=', 1)
    return key.strip(), value.strip()

from math import hypot
from typing import NamedTuple


class Point(NamedTuple):
    x: int
    y: int


def distance_origin(p: Point) -> float:
    return hypot(p.x, p.y)

class Card:
    __slots__ = ('rank', 'suit')

    def __init__(self, rank: str, suit: str) -> None:
        self.rank = rank
        self.suit = suit

    def label(self) -> str:
        return f'{self.rank} of {self.suit}'

def first_long_line(path: str) -> str | None:
    with open(path, encoding='utf-8') as f:
        while line := f.readline():
            if len(line.strip()) > 10:
                return line.strip()
    return None

from typing import Protocol


class Printable(Protocol):
    def __str__(self) -> str: ...


def print_all(items: list[Printable]) -> None:
    for item in items:
        print(str(item))

def factorial(n: int) -> int:
    if n < 0:
        raise ValueError('n must be non-negative')
    result = 1
    for i in range(2, n + 1):
        result *= i
    return result

from collections import deque


def rotate_left(items: list[int], k: int) -> list[int]:
    d = deque(items)
    d.rotate(-k)
    return list(d)

from dataclasses import dataclass


@dataclass
class HttpResponse:
    status: int
    body: str

    def is_ok(self) -> bool:
        return 200 <= self.status < 300
